-- AI_RAG_Agent_Project SQLite -> MySQL 业务数据导入脚本。
-- 使用前请先执行 docs/mysql初始化建表和基础数据.sql。
-- 本脚本只导出现有 SQLite 业务表数据，不包含 Qdrant 向量数据。
-- 注意：本脚本会先清空下列业务表，再导入 SQLite 当前数据，适合一次性迁移。

USE ai_rag_agent;
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
START TRANSACTION;

-- 按外键依赖反向清空表，避免默认字典主键和 SQLite 原始主键混用导致层级错乱。
DELETE FROM `sales_training_scores`;
DELETE FROM `sales_training_turns`;
DELETE FROM `sales_training_sessions`;
DELETE FROM `training_goal_settings`;
DELETE FROM `training_role_profiles`;
DELETE FROM `training_plans`;
DELETE FROM `training_knowledge_batches`;
DELETE FROM `exam_questions`;
DELETE FROM `exam_sessions`;
DELETE FROM `dictionary_items`;
DELETE FROM `conversation_messages`;
DELETE FROM `conversations`;
DELETE FROM `documents`;

