INSERT INTO `conversation_messages` (`message_id`, `conversation_id`, `sequence_no`, `role`, `content`, `content_type`, `model_name`, `token_count`, `metadata_json`, `created_at`) VALUES ('msg_40bf11dba22649e699273fd9b86d354f', 'conv_3c920c3b4b9345649f7b11d26066dc6c', 6, 'assistant', '扫地/扫拖机器人不能在空中工作。它只能在地面上移动和清洁，没有飞行或悬挂功能。', 'text', NULL, NULL, '{"mode": "direct_rag_stream", "first_token_ms": 4156.384099973366, "total_ms": 4265.220000001136}', '2026-06-16 01:55:19') ON DUPLICATE KEY UPDATE `conversation_id` = VALUES(`conversation_id`), `sequence_no` = VALUES(`sequence_no`), `role` = VALUES(`role`), `content` = VALUES(`content`), `content_type` = VALUES(`content_type`), `model_name` = VALUES(`model_name`), `token_count` = VALUES(`token_count`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
