INSERT INTO `conversation_messages` (`message_id`, `conversation_id`, `sequence_no`, `role`, `content`, `content_type`, `model_name`, `token_count`, `metadata_json`, `created_at`) VALUES ('msg_81ea8bc7bbc646638adf86ac68dcffb3', 'conv_3c920c3b4b9345649f7b11d26066dc6c', 26, 'assistant', '根据你的需求，以下是针对不同场景的扫地机器人推荐建议：

1. **小户型/基础清洁需求**：选基础激光导航机型，例如米家或石头品牌的对应型号，性价比高，适合瓷砖、木地板等常见地面。
2. **预算充足/追求省事**：5000元以上可选带自动集尘和热风烘干的高端款，减少手动清理频率。
3. **品牌优先**：建议选科沃斯、石头等一线品牌，品控和售后更完善；小众品牌需确认本地有维修网点。
4. **地面材质注意**：瓷砖、木地板、短毛地毯均可，长毛地毯需确认机器的越障能力。

**提示**：如果预算在3000元内，基础款（激光导航+旋转拖布）已够用。建议先评估房屋面积、地面材质和是否需要自动集尘功能，再选择对应型号。如果需要更具体的推荐，欢迎提供预算和户型信息。', 'text', NULL, NULL, '{"mode": "direct_rag_stream", "first_token_ms": 2928.1197999953292, "total_ms": 4277.8093999950215}', '2026-06-16 03:03:45') ON DUPLICATE KEY UPDATE `conversation_id` = VALUES(`conversation_id`), `sequence_no` = VALUES(`sequence_no`), `role` = VALUES(`role`), `content` = VALUES(`content`), `content_type` = VALUES(`content_type`), `model_name` = VALUES(`model_name`), `token_count` = VALUES(`token_count`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
