INSERT INTO `conversation_messages` (`message_id`, `conversation_id`, `sequence_no`, `role`, `content`, `content_type`, `model_name`, `token_count`, `metadata_json`, `created_at`) VALUES ('msg_53ba1af5f6d54908a4e3fb543b9f2e7f', 'conv_b02d0756f39a48548d663ae990326664', 4, 'assistant', '回复较慢可能与网络或APP运行状态有关。请按以下步骤检查：

1. 确认网络是否正常，尝试切换网络或重启路由器。
2. 检查APP是否开启消息提醒，确保未被系统后台限制。
