INSERT INTO `conversation_messages` (`message_id`, `conversation_id`, `sequence_no`, `role`, `content`, `content_type`, `model_name`, `token_count`, `metadata_json`, `created_at`) VALUES ('msg_652e7062782a4e4983a01ec7c5f36795', 'conv_8675a7772dbd441d9a9122ba2b494264', 6, 'assistant', '我可以帮您解答和处理关于扫地/扫拖机器人的各种问题，具体包括：

