INSERT INTO `exam_questions` (`exam_question_id`, `session_id`, `round_no`, `source_question_id`, `source_document_id`, `source_filename`, `source_page`, `section_path`, `question_type`, `prompt`, `options_json`, `correct_answer_json`, `reference_answer`, `user_answer`, `is_correct`, `score`, `max_score`, `analysis_json`, `status`, `created_at`, `answered_at`) VALUES ('exam_q_6129c9b00aa64812b13ab222f1cf8b7a', 'exam_1dc9785992cc407b99c5ea838b736328', 5, 'doc_56e0087fb19549a3812c7de78744237d_outline_q_0433', 'doc_56e0087fb19549a3812c7de78744237d', 'Java面试题.pdf', 88, 'Redis面试题 / 17、Redis事务', 'single_choice', 'Redis事务
请选择最符合参考答案的一项。', '["功能是通过MULTI、EXEC、DISCARD和WATCH 四个原语实现的 Redis会将一个事务中的所有命令序列化，然后按顺序执行", "NIO 主要有三大核心部分： Channel(通道)， Buﬀer(缓冲区), Selector", "当调用 execute() 方法添加一个任务时，线程池会做如下判断： a) 如果正在运行的线程数量小于 corePoolSize，那么马上创建线程运行这个任务", "\\u0000 模糊特性：自动装配不如显式装配精确，如果有可能，建议使用显式装配"]', '"功能是通过MULTI、EXEC、DISCARD和WATCH 四个原语实现的 Redis会将一个事务中的所有命令序列化，然后按顺序执行"', '功能是通过MULTI、EXEC、DISCARD和WATCH 四个原语实现的
Redis会将一个事务中的所有命令序列化，然后按顺序执行。
1.redis 不支持回滚“Redis 在事务失败时不进行回滚，而是继续执行余下的命令”， 所以 Redis 的内部可以保持简单且快速。
2.如果在一个事务中的命令出现错误，那么所有的命令都不会执行；
3.如果在一个事务中出现运行错误，那么正确的命令会被执行。
1）MULTI命令用于开启一个事务，它总是返回OK。 MULTI执行之后，客户端可以继续向服务器发送任意多条命令，这些命令不会立即被执
行，而是被放到一个队列中，当EXEC命令被调用时，所有队列中的命令才会被执行。
2）EXEC：执行所有事务块内的命令。返回事务块内所有命令的返回值，按命令执行的先后顺序排列。当操作被打断时，返回空值 nil 。
3）通过调用DISCARD，客户端可以清空事务队列，并放弃执行事务， 并且客户端会从事务状态中退出。
4）WATCH 命令可以为 Redis 事务提供 check-and-set （CAS）行为。 可以监控一个或多个键，一旦其中有一个键被修改（或删除），之
后的事务就不会执行，监控一直持续到EXEC命令', '功能是通过MULTI、EXEC、DISCARD和WATCH 四个原语实现的 Redis会将一个事务中的所有命令序列化，然后按顺序执行', 1, 20.0, 20.0, '{"correct_answer": "功能是通过MULTI、EXEC、DISCARD和WATCH 四个原语实现的 Redis会将一个事务中的所有命令序列化，然后按顺序执行", "hit_points": ["功能是通过MULTI、EXEC、DISCARD和WATCH 四个原语实现的 Redis会将一个事务中的所有命令序列化，然后按顺序执行"], "missing_points": [], "wrong_points": [], "comment": "回答正确。"}', 'answered', '2026-06-18 06:58:13', '2026-06-18 06:59:06') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `round_no` = VALUES(`round_no`), `source_question_id` = VALUES(`source_question_id`), `source_document_id` = VALUES(`source_document_id`), `source_filename` = VALUES(`source_filename`), `source_page` = VALUES(`source_page`), `section_path` = VALUES(`section_path`), `question_type` = VALUES(`question_type`), `prompt` = VALUES(`prompt`), `options_json` = VALUES(`options_json`), `correct_answer_json` = VALUES(`correct_answer_json`), `reference_answer` = VALUES(`reference_answer`), `user_answer` = VALUES(`user_answer`), `is_correct` = VALUES(`is_correct`), `score` = VALUES(`score`), `max_score` = VALUES(`max_score`), `analysis_json` = VALUES(`analysis_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `answered_at` = VALUES(`answered_at`);
INSERT INTO `exam_questions` (`exam_question_id`, `session_id`, `round_no`, `source_question_id`, `source_document_id`, `source_filename`, `source_page`, `section_path`, `question_type`, `prompt`, `options_json`, `correct_answer_json`, `reference_answer`, `user_answer`, `is_correct`, `score`, `max_score`, `analysis_json`, `status`, `created_at`, `answered_at`) VALUES ('exam_q_e5648a030f1440038d6877c45a70c330', 'exam_e7c6029dede04ce2a728516c0f1ef374', 1, 'doc_56e0087fb19549a3812c7de78744237d_outline_q_0806', 'doc_56e0087fb19549a3812c7de78744237d', 'Java面试题.pdf', 148, 'Spring Cloud面试题 / 15、微服务的优点缺点?说下开发项目中遇到的坑?', 'true_false', '判断正误：微服务的优点缺点?说下开发项目中遇到的坑?：每个服务直接足够内聚，代码容易理解', '["正确", "错误"]', '"正确"', '优点:
1.每个服务直接足够内聚，代码容易理解
2.开发效率高，一个服务只做一件事，适合小团队开发
3.松耦合，有功能意义的服务。
4.可以用不同语言开发，面向接口编程。
5.易于第三方集成
6.微服务只是业务逻辑的代码，不会和HTML,CSS或其他界面结合.
7.可以灵活搭配，连接公共库/连接独立库
缺点:
1.分布式系统的责任性
2.多服务运维难度加大。
3.系统部署依赖，服务间通信成本，数据一致性，系统集成测试，性能监控。', NULL, NULL, NULL, 20.0, NULL, 'pending', '2026-06-18 06:59:13', NULL) ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `round_no` = VALUES(`round_no`), `source_question_id` = VALUES(`source_question_id`), `source_document_id` = VALUES(`source_document_id`), `source_filename` = VALUES(`source_filename`), `source_page` = VALUES(`source_page`), `section_path` = VALUES(`section_path`), `question_type` = VALUES(`question_type`), `prompt` = VALUES(`prompt`), `options_json` = VALUES(`options_json`), `correct_answer_json` = VALUES(`correct_answer_json`), `reference_answer` = VALUES(`reference_answer`), `user_answer` = VALUES(`user_answer`), `is_correct` = VALUES(`is_correct`), `score` = VALUES(`score`), `max_score` = VALUES(`max_score`), `analysis_json` = VALUES(`analysis_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `answered_at` = VALUES(`answered_at`);
