INSERT INTO `exam_questions` (`exam_question_id`, `session_id`, `round_no`, `source_question_id`, `source_document_id`, `source_filename`, `source_page`, `section_path`, `question_type`, `prompt`, `options_json`, `correct_answer_json`, `reference_answer`, `user_answer`, `is_correct`, `score`, `max_score`, `analysis_json`, `status`, `created_at`, `answered_at`) VALUES ('exam_q_085ab8e423e54d5ca4449fa6e5153bc6', 'exam_e7c6029dede04ce2a728516c0f1ef374', 3, 'doc_56e0087fb19549a3812c7de78744237d_outline_q_0856', 'doc_56e0087fb19549a3812c7de78744237d', 'Java面试题.pdf', 158, 'Dubbo 面试题 / 2、Dubbo 的整体架构设计有哪些分层?', 'single_choice', 'Dubbo 的整体架构设计有哪些分层?
请选择最符合参考答案的一项。', '["接口服务层（Service）：该层与业务逻辑相关，根据 provider 和 consumer 的业务设计对应的接口和实现 配置层（Conﬁg）：对外配置接口，", "很好的与各种数据库兼容（因为 MyBatis 使用 JDBC 来连接数据库，所以只要JDBC 支持的数据库 MyBatis 都支持）", "发送方确认模式 将信道设置成 conﬁrm 模式（发送方确认模式），则所有在信道上发布的消息都会被指派一个唯一的 ID", "流量削峰"]', '"接口服务层（Service）：该层与业务逻辑相关，根据 provider 和 consumer 的业务设计对应的接口和实现 配置层（Conﬁg）：对外配置接口，"', '接口服务层（Service）：该层与业务逻辑相关，根据 provider 和 consumer 的业务设计对应的接口和实现
配置层（Conﬁg）：对外配置接口，以 ServiceConﬁg 和 ReferenceConﬁg 为中心
服务代理层（Proxy）：服务接口透明代理，生成服务的客户端 Stub 和 服务端的 Skeleton，以 ServiceProxy 为中心，扩展接口为 
ProxyFactory
服务注册层（Registry）：封装服务地址的注册和发现，以服务 URL 为中心，扩展接口为 RegistryFactory、Registry、RegistryService
路由层（Cluster）：封装多个提供者的路由和负载均衡，并桥接注册中心，以Invoker 为中心，扩展接口为 Cluster、Directory、Router 
和 LoadBlancce
监控层（Monitor）：RPC 调用次数和调用时间监控，以 Statistics 为中心，扩展接口为 MonitorFactory、Monitor 和 MonitorService
远程调用层（Protocal）：封装 RPC 调用，以 Invocation 和 Result 为中心，扩展接口为 Protocal、Invoker 和 Exporter  
信息交换层（Exchange）：封装请求响应模式，同步转异步。以 Request 和Response 为中心，扩展接口为 Exchanger、
ExchangeChannel、ExchangeClient 和 ExchangeServer
网络传输层（Transport）：抽象 mina 和 netty 为统一接口，以 Message 为中心，扩展接口为 Channel、Transporter、Client、Server 
和 Codec
数据序列化层（Serialize）：可复用的一些工具，扩展接口为 Serialization、ObjectInput、ObjectOutput 和 ThreadPool', NULL, NULL, NULL, 20.0, NULL, 'pending', '2026-06-18 06:59:13', NULL) ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `round_no` = VALUES(`round_no`), `source_question_id` = VALUES(`source_question_id`), `source_document_id` = VALUES(`source_document_id`), `source_filename` = VALUES(`source_filename`), `source_page` = VALUES(`source_page`), `section_path` = VALUES(`section_path`), `question_type` = VALUES(`question_type`), `prompt` = VALUES(`prompt`), `options_json` = VALUES(`options_json`), `correct_answer_json` = VALUES(`correct_answer_json`), `reference_answer` = VALUES(`reference_answer`), `user_answer` = VALUES(`user_answer`), `is_correct` = VALUES(`is_correct`), `score` = VALUES(`score`), `max_score` = VALUES(`max_score`), `analysis_json` = VALUES(`analysis_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `answered_at` = VALUES(`answered_at`);
