INSERT INTO `exam_questions` (`exam_question_id`, `session_id`, `round_no`, `source_question_id`, `source_document_id`, `source_filename`, `source_page`, `section_path`, `question_type`, `prompt`, `options_json`, `correct_answer_json`, `reference_answer`, `user_answer`, `is_correct`, `score`, `max_score`, `analysis_json`, `status`, `created_at`, `answered_at`) VALUES ('exam_q_e1a999ea74614df8ad958efcdaa0340b', 'exam_44067908f79349ca8fd5fb6b0523c464', 5, 'doc_51ca3d8c1ca84e8b84f62b56d8c2abf2_outline_q_0619', 'doc_51ca3d8c1ca84e8b84f62b56d8c2abf2', 'Java面试题.pdf', 110, 'Spring面试题 / 22、什么是 spring 装配', 'single_choice', '关于Spring中的装配（Bean Assembly），以下哪项描述是正确的？', '["A. 装配是指将Spring容器中的多个配置文件合并为一个文件的过程。", "B. 装配是指将多个Spring容器实例合并的过程。", "C. 装配是指将Spring容器中的bean通过依赖注入组合在一起的过程。", "D. 装配是指将Spring的注解配置转换为XML配置的过程。"]', '"C"', '当 bean 在 Spring 容器中组合在一起时，它被称为装配或 bean 装配。Spring容器需要知道需要什么 bean 以及容器应该如何使用依赖注入
来将 bean 绑定在一起，同时装配 bean。  
 
@Configuration
public class StudentConfig {
    @Bean
    public StudentBean myStudent() {
        return new StudentBean();
    }
}
public class Student {
    private Person person;
    //Setters and Getters
} 
public class Person {
    private String name;
    private String address;
    //Setters and Getters
}
<bean id=“StudentBean" class="com.edureka.Student">
    <property name="person">
        <!--This is inner bean -->
        <bean class="com.edureka.Person">
        <property name="name" value=“Scott"></property>
        <property name="address" value=
        “Bangalore"></property>
        </bean>
    </property>
</bean>', NULL, NULL, NULL, 14.2857, NULL, 'pending', '2026-06-23 02:54:44', NULL) ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `round_no` = VALUES(`round_no`), `source_question_id` = VALUES(`source_question_id`), `source_document_id` = VALUES(`source_document_id`), `source_filename` = VALUES(`source_filename`), `source_page` = VALUES(`source_page`), `section_path` = VALUES(`section_path`), `question_type` = VALUES(`question_type`), `prompt` = VALUES(`prompt`), `options_json` = VALUES(`options_json`), `correct_answer_json` = VALUES(`correct_answer_json`), `reference_answer` = VALUES(`reference_answer`), `user_answer` = VALUES(`user_answer`), `is_correct` = VALUES(`is_correct`), `score` = VALUES(`score`), `max_score` = VALUES(`max_score`), `analysis_json` = VALUES(`analysis_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `answered_at` = VALUES(`answered_at`);
INSERT INTO `exam_questions` (`exam_question_id`, `session_id`, `round_no`, `source_question_id`, `source_document_id`, `source_filename`, `source_page`, `section_path`, `question_type`, `prompt`, `options_json`, `correct_answer_json`, `reference_answer`, `user_answer`, `is_correct`, `score`, `max_score`, `analysis_json`, `status`, `created_at`, `answered_at`) VALUES ('exam_q_ecc6ebc2acc345fb8362d214b60e99ea', 'exam_44067908f79349ca8fd5fb6b0523c464', 6, 'doc_51ca3d8c1ca84e8b84f62b56d8c2abf2_outline_q_0855', 'doc_51ca3d8c1ca84e8b84f62b56d8c2abf2', 'Java面试题.pdf', 152, 'RabbitMQ面试题 / 6、消息基于什么传输？', 'single_choice', '在RabbitMQ中，消息的传输是基于什么？', '["A. TCP连接", "B. 信道", "C. 虚拟连接", "D. 消息队列"]', '"B"', '由于 TCP 连接的创建和销毁开销较大，且并发数受系统资源限制，会造成性能瓶颈。RabbitMQ 使用信道的方式来传输数据。信道是建立在
真实的 TCP 连接内的虚拟连接，且每条 TCP 连接上的信道数量没有限制', NULL, NULL, NULL, 14.2857, NULL, 'pending', '2026-06-23 02:54:46', NULL) ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `round_no` = VALUES(`round_no`), `source_question_id` = VALUES(`source_question_id`), `source_document_id` = VALUES(`source_document_id`), `source_filename` = VALUES(`source_filename`), `source_page` = VALUES(`source_page`), `section_path` = VALUES(`section_path`), `question_type` = VALUES(`question_type`), `prompt` = VALUES(`prompt`), `options_json` = VALUES(`options_json`), `correct_answer_json` = VALUES(`correct_answer_json`), `reference_answer` = VALUES(`reference_answer`), `user_answer` = VALUES(`user_answer`), `is_correct` = VALUES(`is_correct`), `score` = VALUES(`score`), `max_score` = VALUES(`max_score`), `analysis_json` = VALUES(`analysis_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `answered_at` = VALUES(`answered_at`);
INSERT INTO `exam_questions` (`exam_question_id`, `session_id`, `round_no`, `source_question_id`, `source_document_id`, `source_filename`, `source_page`, `section_path`, `question_type`, `prompt`, `options_json`, `correct_answer_json`, `reference_answer`, `user_answer`, `is_correct`, `score`, `max_score`, `analysis_json`, `status`, `created_at`, `answered_at`) VALUES ('exam_q_4895affcef1848b29ee3225eae0f853f', 'exam_44067908f79349ca8fd5fb6b0523c464', 7, 'doc_51ca3d8c1ca84e8b84f62b56d8c2abf2_outline_q_0819', 'doc_51ca3d8c1ca84e8b84f62b56d8c2abf2', 'Java面试题.pdf', 144, 'Spring Cloud面试题 / 4、负载平衡的意义什么？', 'single_choice', '关于负载平衡的意义，下列叙述何者最正确？', '["A. 负载平衡是指将单一资源的工作负载平均分配给多个使用者，以降低使用者的负担。", "B. 负载平衡可以改善跨多种计算资源的工作负载分布，优化资源使用，最大化吞吐量，最小化响应时间，并避免单一资源过载。", "C. 负载平衡仅适用于计算机集群，对于网络链接或磁盘驱动器等资源无法应用。", "D. 负载平衡的主要目的是通过减少组件数量来提高系统可靠性，而非通过冗余。"]', '"B"', '在计算中，负载平衡可以改善跨计算机，计算机集群，网络链接，中央处理单元或磁盘驱动器等多种计算资源的工作负载分布。负载平衡旨
在优化资源使用，最大化吞吐量，最小化响应时间并避免任何单一资源的过载。使用多个组件进行负载平衡而不是单个组件可能会通过冗余
来提高可靠性和可用性。负载平衡通常涉及专用软件或硬件，例如多层交换机或域名系统服务器进程。', NULL, NULL, NULL, 14.2857, NULL, 'pending', '2026-06-23 02:54:51', NULL) ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `round_no` = VALUES(`round_no`), `source_question_id` = VALUES(`source_question_id`), `source_document_id` = VALUES(`source_document_id`), `source_filename` = VALUES(`source_filename`), `source_page` = VALUES(`source_page`), `section_path` = VALUES(`section_path`), `question_type` = VALUES(`question_type`), `prompt` = VALUES(`prompt`), `options_json` = VALUES(`options_json`), `correct_answer_json` = VALUES(`correct_answer_json`), `reference_answer` = VALUES(`reference_answer`), `user_answer` = VALUES(`user_answer`), `is_correct` = VALUES(`is_correct`), `score` = VALUES(`score`), `max_score` = VALUES(`max_score`), `analysis_json` = VALUES(`analysis_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `answered_at` = VALUES(`answered_at`);

