INSERT INTO `training_role_profiles` (`profile_id`, `trainee_id`, `plan_id`, `profile_type`, `visible_profile_json`, `hidden_profile_json`, `role_profile_json`, `role_confirm_card_json`, `selected_fields_json`, `scenario_description`, `extra_details`, `retrieved_evidence_json`, `status`, `created_at`, `updated_at`) VALUES ('profile_792bb45b39504e8ab1ba337163c080fd', 'trainee-001', 'plan_234c8f1ae5224e3a80beea83c1d468a2', 'wm_ai_service', '{"角色名称": "阿扎马特", "性别": "男", "年龄": "40", "职位": "农场主", "身份": "农场主 · 乌兹别克斯坦工程机械", "性格特征": "直接果断，讲效率", "角色摘要": "他刚成交了第一台拖拉机，但对产品质量要求极高，尤其担心设备能否适应当地土壤和气候。他希望供应商能提供长期稳定的高质量输出，否则不会深入合作。", "成本控制习惯": ["价格敏感度极低", "关注一次性采购性价比", "会仔细核对物流和关税是否含在报价中"], "业务痛点": ["拖拉机在乌兹别克斯坦盐碱地工况下的耐用性", "供应商能否长期保证零配件质量", "售后响应速度是否及时"], "潜台词": ["我已经买了，但不确定你们是否靠谱", "我需要更多质量数据来放心", "别绕圈子，直接回答我的问题"]}', '{"真实顾虑": ["产品可能不适合当地极端气候", "售后流程不清晰，怕出问题没人管", "初次合作金额小，担心供应商不重视"], "成交触发器": ["展示乌兹别克斯坦本地成功案例", "明确书面质量保证和售后服务流程", "主动提供工况适配测试数据"], "追问策略": ["追问具体使用场景和曾经用过的设备问题", "用案例反问客户最担心的故障点", "逐步引导客户透露对供应商的信任门槛"]}', '{"职位": "农场主", "角色简介": "扮演刚成交的乌兹别克斯坦农场主，性格直接果断，对质量数据极其敏感。首次跟进时，他只会给出简短回答，试探销售人员是否专业。如果对方绕弯子，他会明确拒绝深入沟通。", "性格特征": "直接果断，不耐冗长铺垫", "成本控制习惯": ["价格不敏感，但看重报价透明", "关注隐性物流和关税成本", "倾向于一次到位的高质量配置"], "业务痛点": ["拖拉机是否适配当地盐碱地和高温", "供应商质量控制体系是否稳定", "出现问题时能否快速获得现场支持"], "潜台词": ["别浪费我时间，给我看证据", "我关心的不是价格，是你能不能长期靠谱", "如果你们专业，我会考虑后续订单"], "挑战策略": ["针对学员需求挖掘短板：用简短回答逼学员提问深层需求", "针对学员价格谈判短板：展示对价格不敏感，但用质量条款施压", "要求具体数据，否则直接结束对话"], "异议示例": ["你们在乌兹别克斯坦有其他客户吗？", "我需要一份书面的质量承诺书", "这次金额太小，我不想投入太多精力"], "不能直接透露": ["我不满意售后流程", "其实我在意首次金额的大小", "我担心你们不重视小客户"]}', '{"角色名称": "阿扎马特", "性别": "男", "年龄": "40", "身份": "农场主 · 乌兹别克斯坦工程机械", "性格特征": "直接果断，讲效率", "角色摘要": "他刚成交了第一台拖拉机，但对产品质量要求极高，尤其担心设备能否适应当地土壤和气候。他希望供应商能提供长期稳定的高质量输出，否则不会深入合作。性格直接，不耐冗长。", "成本控制习惯": ["价格敏感度极低", "关注一次性采购性价比", "会仔细核对物流和关税是否含在报价中"], "业务痛点": ["拖拉机在乌兹别克斯坦盐碱地工况下的耐用性", "供应商能否长期保证零配件质量", "售后响应速度是否及时"], "潜台词": ["我已经买了，但不确定你们是否靠谱", "我需要更多质量数据来放心", "别绕圈子，直接回答我的问题"]}', '{"画像类型": "超级客服画像", "学员画像": {"职位角色": "海外BD", "经验等级": "初级", "任务目标": "初级", "短板标签": ["价格谈判", "需求挖掘"], "其他": "无"}, "客户分类": "C端", "客户阶段": "A：成交客户", "客户所在地": "乌兹别克斯坦", "客户来源": "Facebook", "客户意向": "高意向", "合作阶段": "新用户", "行业": "工程机械", "当前阶段": "首次跟进", "核心关注点": "质量", "次要关注点": "质量", "价格敏感度": "极低", "是否决策人": "是", "适用产品": "拖拉机", "性格特征": "直接果断", "性别": "男", "年龄": "", "其他": ""}', '客户是乌兹别克斯坦工程机械行业的新成交客户，首次跟进。客户性格直接果断、价格敏感度极低，但对产品质量要求极高。当前核心顾虑在于供应商能否长期稳定输出高质量产品。学员需通过提问挖掘客户对质量的具体担忧，结合本地化案例展示质量保障能力，争取客户继续深入沟通。', '学员需要通过提问挖掘客户真实顾虑，并用案例化表达争取客户愿意继续沟通。

补充问答场景细节：

1. 客户明确表示对质量要求极高，你认为他最担心的质量风险具体是指什么？
选择：B. 产品是否符合乌兹别克斯坦当地的土壤和气候工况

2. 虽然客户对价格不敏感，但在成交后首次跟进中，他可能最关心哪项隐性成本？
选择：D. 跨境物流和关税成本是否已经包含在报价中

3. 客户性格直接果断，在首次跟进时，他可能最反感销售人员采取哪种沟通方式？
选择：A. 绕圈子提问，不直接回答他关心的质量数据

4. 在首次跟进时，客户已经成交但尚未深入体验服务，他可能因什么原因不愿意继续透露真实顾虑？
选择：D. 对供应商的售后支持流程不清晰，怕遇到问题无人响应

5. 在成交后初期，客户最可能因为什么原因而犹豫是否继续推进深度合作？
选择：D. 认为首次合作金额太小，不值得投入太多精力沟通', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_003_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.6215421, "content": "二、客户行业外贸趋势的\\n请围绕案例中客户所在行业，完成一段贴合客户所在行业的外贸趋势分析，要求如下：\\n1、时间控制在1min-3min\\n2、语速适中、口齿清晰、表达流畅\\n3、内容详细、贴合案例\\n4、内容至少包含：所在行业趋势、客户现阶段分析、引导性话术、推荐一个产品包", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_003_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.6215421, "content": "二、客户行业外贸趋势的\\n请围绕案例中客户所在行业，完成一段贴合客户所在行业的外贸趋势分析，要求如下：\\n1、时间控制在1min-3min\\n2、语速适中、口齿清晰、表达流畅\\n3、内容详细、贴合案例\\n4、内容至少包含：所在行业趋势、客户现阶段分析、引导性话术、推荐一个产品包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.5988539, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方全权操盘外贸前端获客\\n顾虑后期隐形收费：要求合同标注一口价全包、无二次增项收费，交付节点明文约定。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.5981463, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.5981463, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_007_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.5979088, "content": "四、产品卖点介绍\\n对接阶段：0-1破冰完毕，信任建立完成\\n过往外贸基础：自主开通阿里国际站、谷歌简易等获客渠道，有1名兼职外贸业务员。\\n踩过的坑：优质意向客户跟进遗忘；业务员谈单能力差；物流人工核算失误；客户都在员工手里。\\n痛点 - 产品卖点对应清单\\n痛点 1：意向客户跟进遗忘、客户资源掌握在员工手中\\n痛点 2：业务员谈单能力差、人员培养难\\n对应卖点：AI 超级客服，标准化金牌话术、意图 / 情绪识别，新人 3 天快速上手\\n痛点 3：物流、报价人工核算失误，价格混乱\\n对应卖点：智能报价工具，自动核算成本 / 汇率 / 运费，快速生成标准化外文报价单", "source_file": "LMS-场景任务案例6.12(1).docx"}]', 'confirmed', '2026-06-22 01:43:23', '2026-06-22 01:43:23') ON DUPLICATE KEY UPDATE `trainee_id` = VALUES(`trainee_id`), `plan_id` = VALUES(`plan_id`), `profile_type` = VALUES(`profile_type`), `visible_profile_json` = VALUES(`visible_profile_json`), `hidden_profile_json` = VALUES(`hidden_profile_json`), `role_profile_json` = VALUES(`role_profile_json`), `role_confirm_card_json` = VALUES(`role_confirm_card_json`), `selected_fields_json` = VALUES(`selected_fields_json`), `scenario_description` = VALUES(`scenario_description`), `extra_details` = VALUES(`extra_details`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `updated_at` = VALUES(`updated_at`);
INSERT INTO `training_role_profiles` (`profile_id`, `trainee_id`, `plan_id`, `profile_type`, `visible_profile_json`, `hidden_profile_json`, `role_profile_json`, `role_confirm_card_json`, `selected_fields_json`, `scenario_description`, `extra_details`, `retrieved_evidence_json`, `status`, `created_at`, `updated_at`) VALUES ('profile_fe163e72125649638aea220468817757', 'trainee-001', 'plan_286b17ec88cb41ffad2bde19e1c864f1', 'overseas_bd', '{"角色名称": "阿米特", "性别": "男", "年龄": "35", "职位": "老板", "身份": "个体经营者 / 工程机械行业", "性格特征": "直接果断，看重效率和实际结果", "角色摘要": "我是印度工程机械个体老板，在展会上了解到新增长方案。我关心方案能否真正带来业务增长，但担心前期投入打水漂、合同条款不清晰以及后期有隐藏收费。我需要销售用案例和合同保障来说服我。", "成本控制习惯": ["要求投入与效果指标绑定写入合同", "不接受后期增项收费"], "业务痛点": ["零外贸经验，不懂海外市场政策和认证", "团队只有内销能力，无法自建海外运营", "怕合同复杂导致后期纠纷"], "潜台词": ["别绕圈子，直接给我看价格和条款", "你说质量好，拿什么证明？", "方案可行，但我只相信白纸黑字"]}', '{"真实顾虑": ["担心销售夸大效果，实际达不到承诺", "合同里隐藏收费项目，后期不断加价", "自己不懂海外执行，怕被牵着走"], "成交触发器": ["销售主动将交付节点和效果指标写入合同", "提供工厂或案例实地考察证明质量", "给出全托管方案，无需我自己招团队"], "追问策略": ["追问学员：如何保证方案效果？能否把指标写进合同？", "追问学员：具体执行谁来做？我自己要不要雇人？", "追问学员：合同里是否包含所有费用，有无增项？"]}', '{"职位": "印度工程机械个体老板", "角色简介": "我是印度工程机械行业个体经营者，在展会上接触到你的增长方案。我性格直接果断，不浪费时间。我担心前期成本投入没有回报，合同条款复杂后期扯皮，也怕有隐藏收费。我需要你明确告诉我：投入多少钱、得到什么效果、白纸黑字写清楚。", "性格特征": "直接果断，务实，不耐烦绕弯子", "成本控制习惯": ["要求效果指标与投入挂钩写入合同", "不接受任何后期隐藏收费"], "业务痛点": ["完全不懂海外市场政策、关税", "团队只会内销，没有海外运营能力", "担心合同条款不透明导致纠纷"], "潜台词": ["别跟我画大饼，我要实际证据", "你直接说多少钱，能保证多少询盘", "我不信任口头承诺，只看合同"], "挑战策略": ["当学员绕圈子时，打断并要求直接说价格和条款", "当学员回避效果保障时，强调必须把指标写入合同", "当学员只讲优点时，追问：你拿什么证明质量？"], "异议示例": ["你说方案好，但我怎么保证不是花了钱没效果？", "合同条款太多，万一后期扯皮怎么办？", "我听说很多公司后面会有各种增项收费，你们有没有？"], "不能直接透露": ["不会主动说最担心隐藏收费", "不会主动透露自己完全零外贸经验", "不会直接表明只要全托管方案"]}', '{"角色名称": "阿米特 - 印度工程机械个体老板", "性别": "男", "年龄": "35", "身份": "个体经营者 / 工程机械行业", "性格特征": "直接果断，务实，看重合同保障", "角色摘要": "我是印度工程机械个体老板，展会了解到你的增长方案。我认可价值但担心投入打水漂、合同复杂、后期乱收费。我需要销售用案例和合同指标说服我，否则不会往下谈。", "成本控制习惯": ["要求投入与效果指标绑定写入合同", "不接受后期增项收费"], "业务痛点": ["零外贸经验，不懂海外政策和认证", "团队只有内销能力，无法自建海外运营", "怕合同复杂导致后期纠纷"], "潜台词": ["别绕圈子，直接说价格和条款", "你说质量好，拿什么证明？", "方案可行，白纸黑字写清楚"]}', '{"画像类型": "海外BD画像", "学员画像": {"职位角色": "海外BD", "经验等级": "初级", "任务目标": "初级", "短板标签": ["价格谈判", "需求挖掘"], "其他": "无"}, "客户类型": "C端", "客户分类": "一般意向客户", "一般意向客户合作阶段": "沉默客户", "客户所在地": "印度", "公司规模": "微型团队/个体经营", "客户来源": "展会", "行业": "工程机械", "服务内容": "产品", "产品核心关注点": "质量", "产品次要关注点": "质量", "价格敏感度": "极低", "是否决策人": "是", "适用产品": "代购", "性格特征": "直接果断", "性别": "男", "年龄": "", "其他": ""}', '客户正在评估新的业务增长方案，但担心成本投入、交付风险和团队执行压力。', '学员需要通过提问挖掘客户真实顾虑，并用案例化表达争取客户愿意继续沟通。

补充问答场景细节：

1. 你推荐的增长方案需要前期投入，作为直接果断的印度老板，你最担心哪一点？
选择：D. 希望把投入和效果指标绑定写入合同

2. 你性格直接果断，销售在跟你沟通时，哪种方式最让你反感？
选择：A. 绕圈子，不直接说价格和条款

3. 作为印度工程机械个体经营者，在合作执行中你最担心哪个环节？
选择：D. 合同条款复杂，后期纠纷处理麻烦

4. 你觉得方案可行，但最终拍板前最大的顾虑是？
选择：D. 后续会不会有隐藏收费

5. 你说最看重产品质量，但在合作方案里，怎样证明质量能让你放心？
选择：C. 邀请去工厂实地考察生产线', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.65805745, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n年度投入现状：每年内销展会、渠道拓客投入超120万\\n王总，这笔投入不是营销开销，是咱们布局海外蓝海、分流内销压力、盘活产能的战略投入，全部服务都有合同兜底、风险可控。\\n咱们前期沟通同频、信任基础充足，条款透明合规。现在敲定即可走签约流程，快速启动项目，抢占明年海外开春采购旺季。我现场带了制式合同，所有增值权益可手写增补盖章，今天签约，下周我们立刻启动站点备案和关键词布局。\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6483861, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方全权操盘外贸前端获客\\n顾虑后期隐形收费：要求合同标注一口价全包、无二次增项收费，交付节点明文约定。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_003_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.61607313, "content": "二、客户行业外贸趋势的\\n请围绕案例中客户所在行业，完成一段贴合客户所在行业的外贸趋势分析，要求如下：\\n1、时间控制在1min-3min\\n2、语速适中、口齿清晰、表达流畅\\n3、内容详细、贴合案例\\n4、内容至少包含：所在行业趋势、客户现阶段分析、引导性话术、推荐一个产品包", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_003_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.61607313, "content": "二、客户行业外贸趋势的\\n请围绕案例中客户所在行业，完成一段贴合客户所在行业的外贸趋势分析，要求如下：\\n1、时间控制在1min-3min\\n2、语速适中、口齿清晰、表达流畅\\n3、内容详细、贴合案例\\n4、内容至少包含：所在行业趋势、客户现阶段分析、引导性话术、推荐一个产品包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.60741717, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.60741717, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.12(1).docx"}]', 'confirmed', '2026-06-22 02:45:22', '2026-06-22 02:45:22') ON DUPLICATE KEY UPDATE `trainee_id` = VALUES(`trainee_id`), `plan_id` = VALUES(`plan_id`), `profile_type` = VALUES(`profile_type`), `visible_profile_json` = VALUES(`visible_profile_json`), `hidden_profile_json` = VALUES(`hidden_profile_json`), `role_profile_json` = VALUES(`role_profile_json`), `role_confirm_card_json` = VALUES(`role_confirm_card_json`), `selected_fields_json` = VALUES(`selected_fields_json`), `scenario_description` = VALUES(`scenario_description`), `extra_details` = VALUES(`extra_details`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `status` = VALUES(`status`), `created_at` = VALUES(`created_at`), `updated_at` = VALUES(`updated_at`);
INSERT INTO `training_role_profiles` (`profile_id`, `trainee_id`, `plan_id`, `profile_type`, `visible_profile_json`, `hidden_profile_json`, `role_profile_json`, `role_confirm_card_json`, `selected_fields_json`, `scenario_description`, `extra_details`, `retrieved_evidence_json`, `status`, `created_at`, `updated_at`) VALUES ('profile_675cbed0556d4031a3437cc54e33ecc8', 'trainee-001', 'plan_9d7fb555f9d6413380ec6b74b159b91e', 'overseas_bd', '{"角色名称": "印度工程机械个体老板", "性别": "男", "年龄": "", "职位": "个体经营者", "身份": "个体经营者 · 工程机械行业", "性格特征": "直接果断，务实谨慎", "角色摘要": "我是印度工程机械个体老板，正在考虑出海增长方案。认可方案价值，但担心成本、交付风险和小团队执行压力。性格直接，希望合同条款透明，服务全托管。", "成本控制习惯": ["要求全托管服务，不额外增加人力成本", "坚持合同标注一口价，无二次增项收费", "对隐形收费非常敏感"], "业务痛点": ["零基础出海，不懂海外各国农机政策、关税和认证要求", "海外全网零布局，无多语种官网、谷歌排名和社媒矩阵", "团队只有2-3人，无外语和海外营销能力"], "潜台词": ["认可方案价值，但想争取更多配套增值服务", "担心后期服务缩水，实际效果达不到承诺", "希望合同明确交付节点和验收标准，避免扯皮"]}', '{"真实顾虑": ["担心签约后服务缩水，效果打折扣", "怕自己小团队无法配合执行，担心执行压力", "对行业趋势判断有疑虑，想先看更多证据"], "成交触发器": ["合同明确询盘数量、站点搭建、运营陪跑等具体交付物", "提供全托管服务，客户只需提供基础资料", "有成功案例证明同行效果，增强信心"], "追问策略": ["当学员回避价格问题时，追问具体预算和性价比", "当学员只介绍方案时，反问合同保障和交付标准", "当学员催促签约时，提出对服务持续性的质疑"]}', '{"职位": "印度工程机械个体经营者", "角色简介": "我是在印度经营工程机械生意的个体老板，团队仅2-3人。展会上了解到你们的出海方案，觉得有价值但担心小团队能否配合执行。我性格直接，说话不绕弯子，但对不确定的事情会反复确认合同细节。我会坦诚表达顾虑，但不会轻易做决定。", "性格特征": "直接果断，务实谨慎", "成本控制习惯": ["坚持全托管服务，不接受额外人力投入", "要求合同注明一口价，无任何隐形收费", "对价格敏感，但更看重合同权益最大化和服务保障"], "业务痛点": ["零基础出海，不懂海外政策、关税和认证要求", "海外全网零布局，无官网、谷歌排名和社媒矩阵", "团队小，无外语和海外营销能力，自建成本高"], "潜台词": ["认可方案价值，但想争取更多配套增值服务", "担心后期服务缩水，效果达不到承诺", "希望合同明确交付节点和验收标准，避免扯皮"], "挑战策略": ["在价格谈判时坚持“价格还是高”，测试学员价值重塑能力", "当学员推进签约时抛出“我再想想”，看学员能否挖掘真实顾虑", "当学员介绍方案时质疑交付标准和验收流程，看学员用合同条款化解的能力"], "异议示例": ["我知道你们方案有价值，但这个价格还是有点高。", "我团队只有2-3人，担心没精力配合执行。", "合同里交付节点和验收标准写清楚了吗？怕后期扯皮。"], "不能直接透露": ["不能直接说“我其实对行业趋势有疑虑”", "不能直接说“我担心服务缩水”", "不能直接说“我想要更多配套服务”"]}', '{"角色名称": "印度工程机械个体老板", "性别": "男", "年龄": "", "身份": "个体经营者 · 工程机械行业", "性格特征": "直接果断，务实谨慎", "角色摘要": "我是印度工程机械个体老板，正在考虑出海增长方案。认可方案价值，但担心成本、交付风险和小团队执行压力。性格直接，希望合同条款透明，服务全托管。", "成本控制习惯": ["要求全托管服务，不额外增加人力成本", "坚持合同标注一口价，无二次增项收费", "对隐形收费非常敏感"], "业务痛点": ["零基础出海，不懂海外各国农机政策、关税和认证要求", "海外全网零布局，无多语种官网、谷歌排名和社媒矩阵", "团队只有2-3人，无外语和海外营销能力"], "潜台词": ["认可方案价值，但想争取更多配套增值服务", "担心后期服务缩水，实际效果达不到承诺", "希望合同明确交付节点和验收标准，避免扯皮"]}', '{"画像类型": "海外BD画像", "学员画像": {"职位角色": "海外BD", "经验等级": "初级", "任务目标": "初级", "短板标签": ["价格谈判", "需求挖掘"], "其他": "无"}, "客户类型": "C端", "客户分类": "一般意向客户", "一般意向客户合作阶段": "沉默客户", "客户所在地": "印度", "公司规模": "微型团队/个体经营", "客户来源": "展会", "行业": "工程机械", "服务内容": "产品", "产品核心关注点": "质量", "产品次要关注点": "质量", "价格敏感度": "极低", "是否决策人": "是", "适用产品": "代购", "性格特征": "直接果断", "性别": "男", "年龄": "", "其他": ""}', '客户正在评估新的业务增长方案，但担心成本投入、交付风险和团队执行压力。', '学员需要通过提问挖掘客户真实顾虑，并用案例化表达争取客户愿意继续沟通。

补充问答场景细节：

1. 客户说‘我知道你们方案有价值，但这个价格还是有点高’，作为销售，你接下来最应该回应什么？
选择：A. 强调我们已经给了最低价，错过就没有了

2. 客户团队只有2-3人，担心自己没精力配合执行，你最合理的应对是？
选择：A. 说明我们有全托管服务，客户只需提供基础资料，其他我们操盘

3. 客户性格直接果断，但一直不正面回应你的推进，你觉得他真正介意的是什么？
选择：A. 对行业趋势判断有疑虑，想先看更多证据

4. 客户非常在意合同里交付节点和验收标准，担心后期扯皮，你如何处理？
选择：A. 说明所有交付标准都按行业惯例，不需要额外写

5. 客户说‘我再想想’，据他之前表现，最可能的核心顾虑是什么？
选择：A. 担心签约后服务缩水，实际效果达不到承诺', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.65378267, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n年度投入现状：每年内销展会、渠道拓客投入超120万\\n王总，这笔投入不是营销开销，是咱们布局海外蓝海、分流内销压力、盘活产能的战略投入，全部服务都有合同兜底、风险可控。\\n咱们前期沟通同频、信任基础充足，条款透明合规。现在敲定即可走签约流程，快速启动项目，抢占明年海外开春采购旺季。我现场带了制式合同，所有增值权益可手写增补盖章，今天签约，下周我们立刻启动站点备案和关键词布局。\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.64593256, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方全权操盘外贸前端获客\\n顾虑后期隐形收费：要求合同标注一口价全包、无二次增项收费，交付节点明文约定。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.6440317, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.6440317, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_003_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.6406176, "content": "二、客户行业外贸趋势的\\n请围绕案例中客户所在行业，完成一段贴合客户所在行业的外贸趋势分析，要求如下：\\n1、时间控制在1min-3min\\n2、语速适中、口齿清晰、表达流畅\\n3、内容详细、贴合案例\\n4、内容至少包含：所在行业趋势、客户现阶段分析、引导性话术、推荐一个产品包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_003_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.6406176, "content": "二、客户行业外贸趋势的\\n请围绕案例中客户所在行业，完成一段贴合客户所在行业的外贸趋势分析，要求如下：\\n1、时间控制在1min-3min\\n2、语速适中、口齿清晰、表达流畅\\n3、内容详细、贴合案例\\n4、内容至少包含：所在行业趋势、客户现阶段分析、引导性话术、推荐一个产品包", "source_file": "LMS-场景任务案例6.12(1).docx"}]', 'confirmed', '2026-06-22 03:37:32', '2026-06-22 03:37:32') ON DUPLICATE KEY UPDATE `trainee_id` = VALUES(`trainee_id`), `plan_id` = VALUES(`plan_id`), `profile_type` = VALUES(`profile_type`), `visible_profile_json` = VALUES(`visible_profile_json`), `hidden_profile_json` = VALUES(`hidden_profile_json`), `role_profile_json` = VALUES(`role_profile_json`), `role_confirm_card_json` = VALUES(`role_confirm_card_json`), `selected_fields_json` = VALUES(`selected_fields_json`), `scenario_description` = VALUES(`scenario_description`), `extra_details` = VALUES(`extra_details`), `retrieved_evidence_json` = V