INSERT INTO `sales_training_sessions` (`session_id`, `profile_id`, `setting_id`, `trainee_id`, `training_mode`, `response_mode`, `current_stage_no`, `status`, `round_limit`, `total_score`, `level`, `report_json`, `started_at`, `ended_at`, `created_at`, `updated_at`) VALUES ('session_f4715b46cee240b8a5f5816b0f1935d3', 'profile_675cbed0556d4031a3437cc54e33ecc8', 'setting_332b2d00173f4401b1101d9959390706', 'trainee-001', 'open', 'stream', 1, 'completed', 15, 38, '不及格', '{"hit_points": [{"point_name": "信息准确性", "score": 3, "evidence": "对话第2-5轮学员列出了服务内容、价格和案例，但未准确回应对合同交付标准的反复追问。"}, {"point_name": "价值传递", "score": 3, "evidence": "第5轮案例部分关联了客户小团队痛点，但整体价值连接不充分。"}, {"point_name": "流利度", "score": 3, "evidence": "第2-5轮表达基本顺畅，但第1轮严重失误。"}, {"point_name": "专业术语使用", "score": 2, "evidence": "使用了SEO、社媒等术语，但未结合客户场景解释。"}, {"point_name": "证据提供", "score": 4, "evidence": "第5轮提供了两个案例及数据，符合知识证据中案例要求。"}, {"point_name": "价值匹配", "score": 3, "evidence": "第2-3轮提及全托管省心，匹配客户小团队痛点，但未深入。"}], "missing_points": [{"point_name": "需求理解与回应", "score": 0, "evidence": "第1轮学员未理解客户开场信息，反问''你是谁''。"}, {"point_name": "逻辑清晰度", "score": 0, "evidence": "回应顺序混乱，第4轮再次罗列服务而未先回应合同问题。"}, {"point_name": "倾听与承接", "score": 1, "evidence": "第1轮未承接客户情绪，后续对合同条款追问回避。"}, {"point_name": "主动引导", "score": 1, "evidence": "未用问题推进下一步，客户最后仍要求联系案例。"}, {"point_name": "背景追问", "score": 0, "evidence": "未主动询问客户现状、团队分工等。"}, {"point_name": "顾虑挖掘", "score": 0, "evidence": "未引导客户说出对服务缩水等深层担忧。"}, {"point_name": "需求确认", "score": 0, "evidence": "未复述客户核心需求。"}, {"point_name": "风险降低", "score": 1, "evidence": "未提及试点、无责退出等保障措施。"}, {"point_name": "合同透明", "score": 0, "evidence": "未正面回应合同保底询盘数等具体条款。"}, {"point_name": "异议承接", "score": 0, "evidence": "未先认可客户感受（如价格高、怕扯皮）。"}, {"point_name": "针对性回应", "score": 2, "evidence": "对价格有回应，但对合同标准回避。"}, {"point_name": "顾虑化解", "score": 0, "evidence": "未化解客户对合同细节的顾虑。"}, {"point_name": "下一步推进", "score": 0, "evidence": "未提出具体推进动作。"}], "wrong_points": [], "evidence_refs": ["对话第1轮学员反问''你是谁''严重失分", "知识证据中合同保障条款示例（保底询盘、交付节点等）未在学员回应中体现", "标准话术片段（如''保底精准海外采购询盘写入合同''）未被引用"], "improvement_advice": "1. 第一轮必须认真阅读客户开场信息，直接承接，避免反问。2. 客户反复追问合同交付标准时，应正面回应：保底询盘数、上线时间、更新频率等写入合同，并说明未达标赔付机制。3. 先认可客户顾虑（如''您说得对，合同细节必须明确''），再给出具体条款。4. 使用问题引导客户说出深层担忧，如''您最担心哪块服务缩水？''。5. 主动提出下一步：发送合同草案或安排案例客户连线。", "reference_script": "老板，您关注的合同细节我完全理解。第一，每月保底有效询盘数、独立站上线时间、社媒更新频率，全部白纸黑字写入合同附件，未达标按合同约定赔付。第二，年签一口价13500美金，中途绝不加收任何费用。第三，我可以先安排您跟德里Sahil Machines的负责人直接通话，验证实际配合情况。您看是先通话，还是我先把合同草案发给您过目？", "next_training_plan": "1. 专项训练：客户异议承接与合同条款应答。2. 角色扮演：针对客户''怕扯皮''场景，练习用具体合同条款化解。3. 案例复盘：学习标准话术中''保底询盘写入合同''的表述方式。", "scoring_rules": {"total_score": 100, "general_score": 40, "stage_score": 60, "general_dimensions": [{"dimension_name": "内容质量", "score": 20, "points": [{"point_name": "信息准确性", "score": 10, "description": "回答不编造事实，能基于已知客户信息和训练知识表达。"}, {"point_name": "需求理解与回应", "score": 5, "description": "能承接客户问题，不答非所问。"}, {"point_name": "价值传递", "score": 5, "description": "能把方案价值和客户痛点连接起来。"}]}, {"dimension_name": "语言表达", "score": 10, "points": [{"point_name": "流利度", "score": 4, "description": "表达自然顺畅。"}, {"point_name": "专业术语使用", "score": 3, "description": "术语准确，不过度堆砌。"}, {"point_name": "逻辑清晰度", "score": 3, "description": "先回应问题，再给理由和下一步。"}]}, {"dimension_name": "互动与态度", "score": 10, "points": [{"point_name": "倾听与承接", "score": 4, "description": "能接住客户情绪和顾虑。"}, {"point_name": "礼貌与亲和力", "score": 3, "description": "沟通态度专业、尊重客户。"}, {"point_name": "主动引导", "score": 3, "description": "能用问题推进下一步沟通。"}]}], "stage_dimensions": [{"dimension_name": "需求挖掘与痛点确认", "score": 20, "core_goal": "深度理解客户零基础出海背景，精准定位其团队小、无海外运营能力等痛点", "points": [{"point_name": "背景追问", "score": 6, "description": "能主动询问客户当前海外布局情况、团队分工及预算范围"}, {"point_name": "痛点定位", "score": 5, "description": "能准确指出客户零基础、无外语能力、自建成本高等关键痛点"}, {"point_name": "顾虑挖掘", "score": 5, "description": "能引导客户说出对服务缩水、合同保障、执行配合的深层担忧"}, {"point_name": "需求确认", "score": 4, "description": "能复述客户的核心需求和优先级，并确认双方理解一致"}]}, {"dimension_name": "价值呈现与证据支撑", "score": 20, "core_goal": "将方案价值与客户痛点紧密连接，用具体案例和合同条款增强可信度", "points": [{"point_name": "价值匹配", "score": 6, "description": "能将全托管服务的省心特点与客户小团队无精力执行直接关联"}, {"point_name": "证据提供", "score": 5, "description": "能主动分享同行成功案例、询盘数据或海外认证流程的截图"}, {"point_name": "风险降低", "score": 5, "description": "能说明试点机制、分阶段交付或无责退出条款等保障措施"}, {"point_name": "合同透明", "score": 4, "description": "能明确提及合同将注明交付物、验收标准和业绩承诺，打消客户疑虑"}]}, {"dimension_name": "异议处理与推进动作", "score": 20, "core_goal": "承接客户的直接或间接异议，并引导进入签约或试点推进", "points": [{"point_name": "异议承接", "score": 6, "description": "能先认可客户感受（如“您说得对，价格确实需要反复核算”）"}, {"point_name": "针对性回应", "score": 5, "description": "能针对“价格高”提供价值拆解或灵活套餐，而非直接降价"}, {"point_name": "顾虑化解", "score": 5, "description": "能针对“怕后期扯皮”主动提出可写入合同的细化条款"}, {"point_name": "下一步推进", "score": 4, "description": "能提出具体推进动作，如安排线上演示、发送合同草案或约定深度沟通"}]}], "review_mode": "ai_auto", "formula": "总分 = 通用能力得分 + 阶段能力得分 - 扣分；一期暂不启用违规词扣分"}}', '2026-06-22 03:38:25', '2026-06-22 03:42:26', '2026-06-22 03:38:25', '2026-06-22 03:42:26') ON DUPLICATE KEY UPDATE `profile_id` = VALUES(`profile_id`), `setting_id` = VALUES(`setting_id`), `trainee_id` = VALUES(`trainee_id`), `training_mode` = VALUES(`training_mode`), `response_mode` = VALUES(`response_mode`), `current_stage_no` = VALUES(`current_stage_no`), `status` = VALUES(`status`), `round_limit` = VALUES(`round_limit`), `total_score` = VALUES(`total_score`), `level` = VALUES(`level`), `report_json` = VALUES(`report_json`), `started_at` = VALUES(`started_at`), `ended_at` = VALUES(`ended_at`), `created_at` = VALUES(`created_at`), `updated_at` = VALUES(`updated_at`);

