INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_612fccdc30c34a5b878da399acaac2af', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'customer', '之前展会上说的方案确实挺有意思，但我直说了，我们团队就两三个人，真没精力去学一堆海外运营的东西。你们那个全托管服务具体是怎么包的？合同里能写明所有费用和交付时间吗？我不想到时候再扯皮。', 0, 1, 'stream', '2026-06-22 03:38:25', '2026-06-22 03:38:33', NULL, '[]', '[]', '{}', '{}', '{"turn_type": "opening"}', '2026-06-22 03:38:33') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_57e4336944ac46c28ef18c6364a2b0c6', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'trainee', '你是谁', 1, 1, 'stream', '2026-06-22 03:38:47', '2026-06-22 03:38:47', NULL, '[]', '[]', '{}', '{}', '{}', '2026-06-22 03:38:47') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_2b5bf20596954bf0b9e83f9297d53d2d', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'customer', '（略不耐烦）朋友，你这是在逗我？我是展会上跟你聊过出海方案的印度工程机械老板。刚在问你全托管服务具体包什么、合同费用和交付时间能不能写清楚，你倒问起我是谁来了。我没工夫跟你绕，直接说——如果你们全托管能让我这两三个人不用管运营、费用一口价、验收节点白纸黑字写明白，咱们可以往下谈。不然就别浪费我时间。', 1, 1, 'stream', '2026-06-22 03:38:47', '2026-06-22 03:38:55', 7.345, '["batch_222c18d2459f4ab8a1e4f433e314e5b7_006_task_requirement", "batch_58622b9712e242eab7521d3689379394_004_task_requirement", "batch_58622b9712e242eab7521d3689379394_004_case_profile", "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile", "batch_58622b9712e242eab7521d3689379394_003_task_requirement"]', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.4820212, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.4820212, "content": "三、客户痛点诊断的\\n请结合案例中客户的实际情况，分析诊断当前客户痛点，要求如下：\\n1、时间控制在1min-3min\\n2、痛点不少于4个，且贴合案例中客户现状\\n3、沟通话术专业、规范\\n4、由点到面，层层递进，结构化表达\\n5、能够结合当下客户痛点给到初步适配方案或者套餐包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.45819685, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.45812795, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_003_task_requirement", "case_part": "task_requirement", "visibility": "visible", "score": 0.42865527, "content": "二、客户行业外贸趋势的\\n请围绕案例中客户所在行业，完成一段贴合客户所在行业的外贸趋势分析，要求如下：\\n1、时间控制在1min-3min\\n2、语速适中、口齿清晰、表达流畅\\n3、内容详细、贴合案例\\n4、内容至少包含：所在行业趋势、客户现阶段分析、引导性话术、推荐一个产品包", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}]', '{"stage_status": "active", "session_status": "active"}', '{"round_no": 1, "summary": "本轮建议优先补强需求挖掘、证据化表达和下一步推进。", "strengths": ["表达已完成基础回应，但还需要增强销售推进动作。"], "suggestions": ["建议先追问客户当前最核心的顾虑，避免直接进入方案介绍。", "可以补一句同类客户案例、数据或试点路径，让表达更可信。", "结尾建议给出轻量下一步，例如约 15 分钟确认需求或先做小范围验证。"], "retrieval_hint": "本轮命中 5 条训练知识，可结合命中切片补充案例化表达。", "next_reply_hint": "先承接客户顾虑，再追问影响范围，最后用案例或试点降低风险。"}', '{}', '2026-06-22 03:38:55') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_05bab30619e64df19a81aad8fb61c613', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'trainee', '整套出海运营全部交由我方团队承接，您公司仅 2-3 人无需插手日常运营，覆盖海外社媒矩阵运营、独立站搭建 & 运维、谷歌 / 社媒广告投放、询盘筛选分类、海外本地化素材拍摄剪辑、合规售后文案、平台店铺打理、竞品市场监测全流程，日常更新、投放优化、客户咨询前置筛选均由我方专人负责', 2, 1, 'stream', '2026-06-22 03:39:53', '2026-06-22 03:39:53', NULL, '[]', '[]', '{}', '{}', '{}', '2026-06-22 03:39:53') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_100cf95bd82d4d1b84f197aef0698356', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'customer', '行，你这么说我算听明白了。全托管，我这两三个人只管接单，运营你们全包——签合同之前我得跟你掰扯清楚：第一，这整套服务报个具体价，别跟我玩区间报价；第二，合同里必须白纸黑字写明每月保底询盘数、站点什么时候上线、社媒更新频率，验收标准一条条列清楚；第三，有没有跟我差不多规模的印度客户做成过的案例？让我看看实际效果，别光说得好听。', 2, 1, 'stream', '2026-06-22 03:39:53', '2026-06-22 03:39:59', 5.551, '["batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "batch_58622b9712e242eab7521d3689379394_006_case_profile", "batch_58622b9712e242eab7521d3689379394_004_case_profile", "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile"]', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6911371, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n年度投入现状：每年内销展会、渠道拓客投入超120万\\n王总，这笔投入不是营销开销，是咱们布局海外蓝海、分流内销压力、盘活产能的战略投入，全部服务都有合同兜底、风险可控。\\n咱们前期沟通同频、信任基础充足，条款透明合规。现在敲定即可走签约流程，快速启动项目，抢占明年海外开春采购旺季。我现场带了制式合同，所有增值权益可手写增补盖章，今天签约，下周我们立刻启动站点备案和关键词布局。\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "case_part": "standard_answer", "visibility": "visible", "score": 0.67654544, "content": "五、成单话术\\n套餐适配：L5五星旗舰版 ¥199800/年（行业头部、全球化布局、标杆出海专属）\\n我直接给您对标性价比：咱们工厂每年内销拓客、展会投入超120万，成本高、回款慢、行业内卷严重。而我们L5五星旗舰版，全年一口价仅199800元，只相当于您内销单月拓客成本的六分之一。\\n这笔投入，能一次性补齐您所有外贸短板，解决海外无品牌、无站点、无团队、不懂海外市场的核心问题。自主搭建外贸体系成本高、试错风险大，很容易投入打水漂。咱们全托管套餐，所有运营风险、试错成本全部由我方承担，性价比和安全性远超自主出海。\\n再跟您明确合同白纸黑字的四大保障，彻底打消您的顾虑。第一，保底精准海外采购询盘、32语种全域独立站、谷歌AI关键词占位、海外品牌打造，全部写入合同，未达标直接赔付。\\n第二，一口价全包所有服务，建站、域名、运维、社媒运营、高管陪跑、外贸赋能全覆盖，终身无隐形收费。第三，适配您零外贸团队模式，我们全程全权操盘，您无需招人、无需懂运营，现有内勤即可对接接单。第四，所有服务分阶段定时交付，同时免费赠送农机海外合规资料、客商对接话术库专属权益。", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6717415, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方全权操盘外贸前端获客\\n顾虑后期隐形收费：要求合同标注一口价全包、无二次增项收费，交付节点明文约定。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6204692, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6203463, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.12(1).docx"}]', '{"stage_status": "active", "session_status": "active"}', '{"round_no": 2, "summary": "本轮建议优先补强需求挖掘、证据化表达和下一步推进。", "strengths": ["本轮尝试使用证据或案例降低客户不确定感。"], "suggestions": ["建议先追问客户当前最核心的顾虑，避免直接进入方案介绍。", "结尾建议给出轻量下一步，例如约 15 分钟确认需求或先做小范围验证。"], "retrieval_hint": "本轮命中 5 条训练知识，可结合命中切片补充案例化表达。", "next_reply_hint": "先承接客户顾虑，再追问影响范围，最后用案例或试点降低风险。"}', '{}', '2026-06-22 03:39:59') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_022ff9454df14b78845a90fca99b4045', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'trainee', '多语种营销独立站搭建、服务器、域名、全年运维、产品上架迭代；
Google 印度区 SEO + 竞价广告基础投放优化、关键词拓词、出价调整；
LinkedIn/YouTube/Instagram 印度工程机械社媒全运营；
印地语 + 英语本地化文案、设备实拍剪辑、产品海报月度产出；
询盘统一承接、前置筛选、垃圾询盘过滤，只推送采购意向客户；
月度数据复盘报表、印度工程机械竞品行情监测、BIS 合规资料协助；
专属运营小组 1 名海外投放专员 + 1 名内容编辑对接您，您团队仅负责成交洽谈', 3, 1, 'stream', '2026-06-22 03:40:31', '2026-06-22 03:40:31', NULL, '[]', '[]', '{}', '{}', '{}', '2026-06-22 03:40:31') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_7749227b3f944e24be25dac6a03a3705', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'customer', '服务内容你列得够细，这些我认。兄弟，我直接说——你报个具体价，别跟我说什么区间或者根据情况浮动。我两三个人出海，钱要花在刀刃上。合同里每月保底询盘数、站点上线时间、社媒更新频率，白纸黑字一条条写清楚。另外，你手头有没有跟我差不多规模的印度工程机械老板做成功的？拿个案例让我看看实际效果，别光嘴上说得好听。', 3, 1, 'stream', '2026-06-22 03:40:31', '2026-06-22 03:40:37', 6.093, '["batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "batch_58622b9712e242eab7521d3689379394_006_case_profile", "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "batch_222c18d2459f4ab8a1e4f433e314e5b7_007_case_profile", "batch_58622b9712e242eab7521d3689379394_005_case_profile"]', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6494001, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n年度投入现状：每年内销展会、渠道拓客投入超120万\\n王总，这笔投入不是营销开销，是咱们布局海外蓝海、分流内销压力、盘活产能的战略投入，全部服务都有合同兜底、风险可控。\\n咱们前期沟通同频、信任基础充足，条款透明合规。现在敲定即可走签约流程，快速启动项目，抢占明年海外开春采购旺季。我现场带了制式合同，所有增值权益可手写增补盖章，今天签约，下周我们立刻启动站点备案和关键词布局。\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6415781, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方全权操盘外贸前端获客\\n顾虑后期隐形收费：要求合同标注一口价全包、无二次增项收费，交付节点明文约定。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "case_part": "standard_answer", "visibility": "visible", "score": 0.59021246, "content": "五、成单话术\\n套餐适配：L5五星旗舰版 ¥199800/年（行业头部、全球化布局、标杆出海专属）\\n我直接给您对标性价比：咱们工厂每年内销拓客、展会投入超120万，成本高、回款慢、行业内卷严重。而我们L5五星旗舰版，全年一口价仅199800元，只相当于您内销单月拓客成本的六分之一。\\n这笔投入，能一次性补齐您所有外贸短板，解决海外无品牌、无站点、无团队、不懂海外市场的核心问题。自主搭建外贸体系成本高、试错风险大，很容易投入打水漂。咱们全托管套餐，所有运营风险、试错成本全部由我方承担，性价比和安全性远超自主出海。\\n再跟您明确合同白纸黑字的四大保障，彻底打消您的顾虑。第一，保底精准海外采购询盘、32语种全域独立站、谷歌AI关键词占位、海外品牌打造，全部写入合同，未达标直接赔付。\\n第二，一口价全包所有服务，建站、域名、运维、社媒运营、高管陪跑、外贸赋能全覆盖，终身无隐形收费。第三，适配您零外贸团队模式，我们全程全权操盘，您无需招人、无需懂运营，现有内勤即可对接接单。第四，所有服务分阶段定时交付，同时免费赠送农机海外合规资料、客商对接话术库专属权益。", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_007_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.58482075, "content": "四、产品卖点介绍\\n对接阶段：0-1破冰完毕，信任建立完成\\n过往外贸基础：自主开通阿里国际站、谷歌简易等获客渠道，有1名兼职外贸业务员。\\n踩过的坑：优质意向客户跟进遗忘；业务员谈单能力差；物流人工核算失误；客户都在员工手里。\\n痛点 - 产品卖点对应清单\\n痛点 1：意向客户跟进遗忘、客户资源掌握在员工手中\\n痛点 2：业务员谈单能力差、人员培养难\\n对应卖点：AI 超级客服，标准化金牌话术、意图 / 情绪识别，新人 3 天快速上手\\n痛点 3：物流、报价人工核算失误，价格混乱\\n对应卖点：智能报价工具，自动核算成本 / 汇率 / 运费，快速生成标准化外文报价单", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_005_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.5687113, "content": "四、产品卖点介绍\\n对接阶段：0-1破冰完毕，信任建立完成\\n过往外贸基础：自主开通阿里国际站、谷歌简易等获客渠道，有1名兼职外贸业务员。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}]', '{"stage_status": "active", "session_status": "active"}', '{"round_no": 3, "summary": "本轮建议优先补强需求挖掘、证据化表达和下一步推进。", "strengths": ["本轮尝试使用证据或案例降低客户不确定感。"], "suggestions": ["建议先追问客户当前最核心的顾虑，避免直接进入方案介绍。", "结尾建议给出轻量下一步，例如约 15 分钟确认需求或先做小范围验证。"], "retrieval_hint": "本轮命中 5 条训练知识，可结合命中切片补充案例化表达。", "next_reply_hint": "先承接客户顾虑，再追问影响范围，最后用案例或试点降低风险。"}', '{}', '2026-06-22 03:40:37') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_9aa207e3a8244bd29f4496111face7d0', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'trainee', '针对您 2-3 人小规模工程机械、纯印度市场出海全托管，固定月度一口价 1260 美金 / 月；年签打包总价 13500 美金（相当于 10.7 个月费用，送 1 个月免费运营）。
合同附件明确全包边界（中途绝不额外加收运营服务费）
印度本地化 B2B 营销独立站：域名、海外服务器、建站开发、全年运维、产品上下架、页面迭代；
Google 印度区全套投放：SEO 自然优化 + 搜索竞价广告基础预算优化、关键词拓词、出价调整、负面关键词屏蔽；
三大社媒全托管：LinkedIn（工程采购决策人）+YouTube 设备短视频 + Facebook/Instagram 印度基建行业账号；
本地化内容产出：英文 + 印地语文案、设备实拍剪辑、产品海报、行业技术白皮书；
询盘全流程前置处理：海外客户咨询承接、基础技术答疑、垃圾询盘过滤，仅推送真实采购意向客户给到您团队；
月度完整复盘报表、印度工程机械竞品监测、BIS 合规文案协助、专属 1 对 1 运营专员对接', 4, 1, 'stream', '2026-06-22 03:41:15', '2026-06-22 03:41:15', NULL, '[]', '[]', '{}', '{}', '{}', '2026-06-22 03:41:15') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_82ac322893834e0b927877d7dec74510', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'customer', '价格说清楚了，这点我认。但你光把服务列出来还不够——我反复问的合同里每月保底询盘数、站点什么时候上线、社媒每周更新几条，你一条都没正面回答。白纸黑字没写清楚，我怎么敢签？另外，你说年签省一个月，13500美金也不少了，我两三个人做生意，投出去的水不能打水漂。先拿个同等规模的印度客户案例给我看看，再说合同交付节点的事，不然我心里没底。', 4, 1, 'stream', '2026-06-22 03:41:15', '2026-06-22 03:41:20', 4.745, '["batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "batch_58622b9712e242eab7521d3689379394_006_case_profile", "batch_58622b9712e242eab7521d3689379394_004_case_profile", "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile"]', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6481111, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n年度投入现状：每年内销展会、渠道拓客投入超120万\\n王总，这笔投入不是营销开销，是咱们布局海外蓝海、分流内销压力、盘活产能的战略投入，全部服务都有合同兜底、风险可控。\\n咱们前期沟通同频、信任基础充足，条款透明合规。现在敲定即可走签约流程，快速启动项目，抢占明年海外开春采购旺季。我现场带了制式合同，所有增值权益可手写增补盖章，今天签约，下周我们立刻启动站点备案和关键词布局。\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "case_part": "standard_answer", "visibility": "visible", "score": 0.64751637, "content": "五、成单话术\\n套餐适配：L5五星旗舰版 ¥199800/年（行业头部、全球化布局、标杆出海专属）\\n我直接给您对标性价比：咱们工厂每年内销拓客、展会投入超120万，成本高、回款慢、行业内卷严重。而我们L5五星旗舰版，全年一口价仅199800元，只相当于您内销单月拓客成本的六分之一。\\n这笔投入，能一次性补齐您所有外贸短板，解决海外无品牌、无站点、无团队、不懂海外市场的核心问题。自主搭建外贸体系成本高、试错风险大，很容易投入打水漂。咱们全托管套餐，所有运营风险、试错成本全部由我方承担，性价比和安全性远超自主出海。\\n再跟您明确合同白纸黑字的四大保障，彻底打消您的顾虑。第一，保底精准海外采购询盘、32语种全域独立站、谷歌AI关键词占位、海外品牌打造，全部写入合同，未达标直接赔付。\\n第二，一口价全包所有服务，建站、域名、运维、社媒运营、高管陪跑、外贸赋能全覆盖，终身无隐形收费。第三，适配您零外贸团队模式，我们全程全权操盘，您无需招人、无需懂运营，现有内勤即可对接接单。第四，所有服务分阶段定时交付，同时免费赠送农机海外合规资料、客商对接话术库专属权益。", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.64537203, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方全权操盘外贸前端获客\\n顾虑后期隐形收费：要求合同标注一口价全包、无二次增项收费，交付节点明文约定。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.5805165, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.580296, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.12(1).docx"}]', '{"stage_status": "active", "session_status": "active"}', '{"round_no": 4, "summary": "本轮建议优先补强需求挖掘、证据化表达和下一步推进。", "strengths": ["本轮尝试使用证据或案例降低客户不确定感。"], "suggestions": ["建议先追问客户当前最核心的顾虑，避免直接进入方案介绍。", "结尾建议给出轻量下一步，例如约 15 分钟确认需求或先做小范围验证。"], "retrieval_hint": "本轮命中 5 条训练知识，可结合命中切片补充案例化表达。", "next_reply_hint": "先承接客户顾虑，再追问影响范围，最后用案例或试点降低风险。"}', '{}', '2026-06-22 03:41:20') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_7721ac39477e449581a9146f384ee837', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'trainee', '案例 1：Sahil Machines（德里小型工程设备厂商，销售团队仅 3 人，无专职线上运营）
合作背景：只靠线下展会获客，线上完全空白，人手紧张，希望运营全托管，团队只负责接单谈单；
服务模式：和你咨询的同款印度市场全托管，年签 13500 美金一口价套餐；
硬性交付落地（完全按下面合同标准执行）：
签约收齐资料后 19 个工作日独立站正式上线，无延期；
社媒严格按固定频次更新，每月提前交付排期；
上线次月起每月保底 32 条有效采购询盘；
12 个月真实运营成果：
谷歌自然月访客稳定 420 + 印度基建承包商、租赁商；
月均有效询盘 40~55 条，全年线上转化 18 笔整机批量采购订单，线上营收占总业绩 47%；
可提供核验材料：网站后台流量截图、完整月度询盘台账、YouTube 成品短视频、合作对接人联系方式，你可直接沟通核实效果。
案例 2：Pahel Agrotech（苏拉特农用基建机械厂商，仅 2 人销售团队）
合作周期 8 个月，全套全托管服务；
投放 & 社媒数据：Meta 社媒总曝光 596 万 +，Google 精准覆盖印度各邦工程采购商，8 个月累计有效询盘 4272 条，WhatsApp 高意向采购咨询 592 条，线上渠道贡献 57.62% 成交订单；
落地佐证：完整月度投放看板、印地语本地化短视频样片、每月询盘明细报表全部可发你查阅。
两个客户都是仅 2-3 人团队，没有专职运营，全程只对接精准采购询盘，和你现在的需求、规模高度吻合，不是大型工厂注水案例。', 5, 1, 'stream', '2026-06-22 03:41:59', '2026-06-22 03:41:59', NULL, '[]', '[]', '{}', '{}', '{}', '2026-06-22 03:41:59') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);
INSERT INTO `sales_training_turns` (`turn_id`, `session_id`, `role`, `content`, `round_no`, `stage_no`, `response_mode`, `started_at`, `submitted_at`, `response_seconds`, `retrieved_chunk_ids_json`, `retrieved_evidence_json`, `stage_decision_json`, `coach_analysis_json`, `metadata_json`, `created_at`) VALUES ('turn_52a806cec4f44b2890dddaa034b4a517', 'session_f4715b46cee240b8a5f5816b0f1935d3', 'customer', '案例我看了，德里那个Sahil Machines跟我规模差不多，数据确实有料，这点我不否认。但你话说回来——我心里那个疙瘩还是没解开。合同里每月保底询盘数、站点上线天数、社媒更新频率，你一条都没白纸黑字承诺给我。跟案例里一样，我就要也写进合同，没达标怎么赔。还有，你直接把Sahil负责人的联系方式给我，我打个电话问问他实际配合起来是不是你说的那么省心。这两点落实了，我才能往下推进。', 5, 1, 'stream', '2026-06-22 03:41:59', '2026-06-22 03:42:03', 4.341, '["batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "batch_58622b9712e242eab7521d3689379394_006_case_profile", "batch_58622b9712e242eab7521d3689379394_004_case_profile", "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile"]', '[{"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_standard_answer", "case_part": "standard_answer", "visibility": "visible", "score": 0.6287976, "content": "五、成单话术\\n套餐适配：L5五星旗舰版 ¥199800/年（行业头部、全球化布局、标杆出海专属）\\n我直接给您对标性价比：咱们工厂每年内销拓客、展会投入超120万，成本高、回款慢、行业内卷严重。而我们L5五星旗舰版，全年一口价仅199800元，只相当于您内销单月拓客成本的六分之一。\\n这笔投入，能一次性补齐您所有外贸短板，解决海外无品牌、无站点、无团队、不懂海外市场的核心问题。自主搭建外贸体系成本高、试错风险大，很容易投入打水漂。咱们全托管套餐，所有运营风险、试错成本全部由我方承担，性价比和安全性远超自主出海。\\n再跟您明确合同白纸黑字的四大保障，彻底打消您的顾虑。第一，保底精准海外采购询盘、32语种全域独立站、谷歌AI关键词占位、海外品牌打造，全部写入合同，未达标直接赔付。\\n第二，一口价全包所有服务，建站、域名、运维、社媒运营、高管陪跑、外贸赋能全覆盖，终身无隐形收费。第三，适配您零外贸团队模式，我们全程全权操盘，您无需招人、无需懂运营，现有内勤即可对接接单。第四，所有服务分阶段定时交付，同时免费赠送农机海外合规资料、客商对接话术库专属权益。", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_008_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6236464, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n年度投入现状：每年内销展会、渠道拓客投入超120万\\n王总，这笔投入不是营销开销，是咱们布局海外蓝海、分流内销压力、盘活产能的战略投入，全部服务都有合同兜底、风险可控。\\n咱们前期沟通同频、信任基础充足，条款透明合规。现在敲定即可走签约流程，快速启动项目，抢占明年海外开春采购旺季。我现场带了制式合同，所有增值权益可手写增补盖章，今天签约，下周我们立刻启动站点备案和关键词布局。\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方", "source_file": "LMS-场景任务案例6.12(1).docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.6221589, "content": "五、成单话术\\n老板意向：对销售的专业度信任度较高、认同出海布局必要性、有明确合作意向。\\n团队规模：220人成熟团队，全年总营收3.2亿人民币\\n意向产品：L5五星旗舰版\\n主营品类：电动割草机、小型开荒农机、农用除草机\\n外贸经验：0-1阶段\\n信息卡点：零基础出海，不懂全球各区域农机政策、关税、认证要求，分不清欧美高端农机、东南亚平价农机、中东工程农机的市场差异，完全无出海研判能力；\\n渠道卡点：海外全网零布局，无多语种官网、无谷歌排名、无AI供应商背书、无海外社媒矩阵，海外采购商、海外农资经销商完全检索不到本厂；\\n同行卡点：本土头部同行已提前布局谷歌+AI+海外短视频全域获客，抢占海外农机采购流量，本厂滞后入局，零散小套餐无法追赶同行布局体量；\\n团队卡点：自有员工只会内销跟单、国内业务谈判，无外语、无海外营销、无海外谈判能力，自建全球化外贸运营团队年人力成本超60万，成本极高；\\n战略卡点：老板不想低成本试水小语种、小众国家，想要直接打造全球化自主品牌，对标国际农机厂商，抢占行业头部席位，缺少一站式全域出海落地服务商。\\n客户老板核心现状&心理诉求（核心0-1出海阶段）：\\n不是拒绝合作，属于实业老板正常议价：认可价值，但想要价格适配工厂预算、合同权益最大化，争取配套增值服务；\\n极度看重合同履约保障：要求询盘数量、站点搭建、全域运营、陪跑服务全部写入合同，规避后期服务缩水；\\n不想额外增加人力成本：需要全托管服务，我方全权操盘外贸前端获客\\n顾虑后期隐形收费：要求合同标注一口价全包、无二次增项收费，交付节点明文约定。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_58622b9712e242eab7521d3689379394_004_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.58590513, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.11（替换文案）.docx"}, {"chunk_id": "batch_222c18d2459f4ab8a1e4f433e314e5b7_006_case_profile", "case_part": "case_profile", "visibility": "visible", "score": 0.585685, "content": "三、客户痛点诊断的\\n团队规模：10-20人工贸结合外贸团队\\n年度营收：外贸年营收268万人民币，纯海外B2B批发，主打海外家装公司\\n主营品类：家居装饰灯具\\n现有线上资产：仅搭建简易模板独立站；页面排版老旧、产品分类混乱。\\n年度获客成本：16.2万/年，线上获客成本极高。", "source_file": "LMS-场景任务案例6.12(1).docx"}]', '{"stage_status": "active", "session_status": "active"}', '{"round_no": 5, "summary": "本轮建议优先补强需求挖掘、证据化表达和下一步推进。", "strengths": ["本轮尝试使用证据或案例降低客户不确定感。", "本轮有下一步推进意识。"], "suggestions": ["建议先追问客户当前最核心的顾虑，避免直接进入方案介绍。"], "retrieval_hint": "本轮命中 5 条训练知识，可结合命中切片补充案例化表达。", "next_reply_hint": "先承接客户顾虑，再追问影响范围，最后用案例或试点降低风险。"}', '{}', '2026-06-22 03:42:03') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `role` = VALUES(`role`), `content` = VALUES(`content`), `round_no` = VALUES(`round_no`), `stage_no` = VALUES(`stage_no`), `response_mode` = VALUES(`response_mode`), `started_at` = VALUES(`started_at`), `submitted_at` = VALUES(`submitted_at`), `response_seconds` = VALUES(`response_seconds`), `retrieved_chunk_ids_json` = VALUES(`retrieved_chunk_ids_json`), `retrieved_evidence_json` = VALUES(`retrieved_evidence_json`), `stage_decision_json` = VALUES(`stage_decision_json`), `coach_analysis_json` = VALUES(`coach_analysis_json`), `metadata_json` = VALUES(`metadata_json`), `created_at` = VALUES(`created_at`);

-- 表数据：sales_training_scores，共 1 条
INSERT INTO `sales_training_scores` (`score_id`, `session_id`, `general_score`, `stage_score`, `penalty_score`, `final_score`, `level`, `is_passed`, `detail_json`, `review_status`, `created_at`, `updated_at`) VALUES ('score_fd9ead2e3d4e445c90ec1377cbcac0b7', 'session_f4715b46cee240b8a5f5816b0f1935d3', 17, 21, 0, 38, '不及格', 0, '{"hit_points": [{"point_name": "信息准确性", "score": 3, "evidence": "对话第2-5轮学员列出了服务内容、价格和案例，但未准确回应对合同交付标准的反复追问。"}, {"point_name": "价值传递", "score": 3, "evidence": "第5轮案例部分关联了客户小团队痛点，但整体价值连接不充分。"}, {"point_name": "流利度", "score": 3, "evidence": "第2-5轮表达基本顺畅，但第1轮严重失误。"}, {"point_name": "专业术语使用", "score": 2, "evidence": "使用了SEO、社媒等术语，但未结合客户场景解释。"}, {"point_name": "证据提供", "score": 4, "evidence": "第5轮提供了两个案例及数据，符合知识证据中案例要求。"}, {"point_name": "价值匹配", "score": 3, "evidence": "第2-3轮提及全托管省心，匹配客户小团队痛点，但未深入。"}], "missing_points": [{"point_name": "需求理解与回应", "score": 0, "evidence": "第1轮学员未理解客户开场信息，反问''你是谁''。"}, {"point_name": "逻辑清晰度", "score": 0, "evidence": "回应顺序混乱，第4轮再次罗列服务而未先回应合同问题。"}, {"point_name": "倾听与承接", "score": 1, "evidence": "第1轮未承接客户情绪，后续对合同条款追问回避。"}, {"point_name": "主动引导", "score": 1, "evidence": "未用问题推进下一步，客户最后仍要求联系案例。"}, {"point_name": "背景追问", "score": 0, "evidence": "未主动询问客户现状、团队分工等。"}, {"point_name": "顾虑挖掘", "score": 0, "evidence": "未引导客户说出对服务缩水等深层担忧。"}, {"point_name": "需求确认", "score": 0, "evidence": "未复述客户核心需求。"}, {"point_name": "风险降低", "score": 1, "evidence": "未提及试点、无责退出等保障措施。"}, {"point_name": "合同透明", "score": 0, "evidence": "未正面回应合同保底询盘数等具体条款。"}, {"point_name": "异议承接", "score": 0, "evidence": "未先认可客户感受（如价格高、怕扯皮）。"}, {"point_name": "针对性回应", "score": 2, "evidence": "对价格有回应，但对合同标准回避。"}, {"point_name": "顾虑化解", "score": 0, "evidence": "未化解客户对合同细节的顾虑。"}, {"point_name": "下一步推进", "score": 0, "evidence": "未提出具体推进动作。"}], "wrong_points": [], "evidence_refs": ["对话第1轮学员反问''你是谁''严重失分", "知识证据中合同保障条款示例（保底询盘、交付节点等）未在学员回应中体现", "标准话术片段（如''保底精准海外采购询盘写入合同''）未被引用"], "improvement_advice": "1. 第一轮必须认真阅读客户开场信息，直接承接，避免反问。2. 客户反复追问合同交付标准时，应正面回应：保底询盘数、上线时间、更新频率等写入合同，并说明未达标赔付机制。3. 先认可客户顾虑（如''您说得对，合同细节必须明确''），再给出具体条款。4. 使用问题引导客户说出深层担忧，如''您最担心哪块服务缩水？''。5. 主动提出下一步：发送合同草案或安排案例客户连线。", "reference_script": "老板，您关注的合同细节我完全理解。第一，每月保底有效询盘数、独立站上线时间、社媒更新频率，全部白纸黑字写入合同附件，未达标按合同约定赔付。第二，年签一口价13500美金，中途绝不加收任何费用。第三，我可以先安排您跟德里Sahil Machines的负责人直接通话，验证实际配合情况。您看是先通话，还是我先把合同草案发给您过目？", "next_training_plan": "1. 专项训练：客户异议承接与合同条款应答。2. 角色扮演：针对客户''怕扯皮''场景，练习用具体合同条款化解。3. 案例复盘：学习标准话术中''保底询盘写入合同''的表述方式。", "scoring_rules": {"total_score": 100, "general_score": 40, "stage_score": 60, "general_dimensions": [{"dimension_name": "内容质量", "score": 20, "points": [{"point_name": "信息准确性", "score": 10, "description": "回答不编造事实，能基于已知客户信息和训练知识表达。"}, {"point_name": "需求理解与回应", "score": 5, "description": "能承接客户问题，不答非所问。"}, {"point_name": "价值传递", "score": 5, "description": "能把方案价值和客户痛点连接起来。"}]}, {"dimension_name": "语言表达", "score": 10, "points": [{"point_name": "流利度", "score": 4, "description": "表达自然顺畅。"}, {"point_name": "专业术语使用", "score": 3, "description": "术语准确，不过度堆砌。"}, {"point_name": "逻辑清晰度", "score": 3, "description": "先回应问题，再给理由和下一步。"}]}, {"dimension_name": "互动与态度", "score": 10, "points": [{"point_name": "倾听与承接", "score": 4, "description": "能接住客户情绪和顾虑。"}, {"point_name": "礼貌与亲和力", "score": 3, "description": "沟通态度专业、尊重客户。"}, {"point_name": "主动引导", "score": 3, "description": "能用问题推进下一步沟通。"}]}], "stage_dimensions": [{"dimension_name": "需求挖掘与痛点确认", "score": 20, "core_goal": "深度理解客户零基础出海背景，精准定位其团队小、无海外运营能力等痛点", "points": [{"point_name": "背景追问", "score": 6, "description": "能主动询问客户当前海外布局情况、团队分工及预算范围"}, {"point_name": "痛点定位", "score": 5, "description": "能准确指出客户零基础、无外语能力、自建成本高等关键痛点"}, {"point_name": "顾虑挖掘", "score": 5, "description": "能引导客户说出对服务缩水、合同保障、执行配合的深层担忧"}, {"point_name": "需求确认", "score": 4, "description": "能复述客户的核心需求和优先级，并确认双方理解一致"}]}, {"dimension_name": "价值呈现与证据支撑", "score": 20, "core_goal": "将方案价值与客户痛点紧密连接，用具体案例和合同条款增强可信度", "points": [{"point_name": "价值匹配", "score": 6, "description": "能将全托管服务的省心特点与客户小团队无精力执行直接关联"}, {"point_name": "证据提供", "score": 5, "description": "能主动分享同行成功案例、询盘数据或海外认证流程的截图"}, {"point_name": "风险降低", "score": 5, "description": "能说明试点机制、分阶段交付或无责退出条款等保障措施"}, {"point_name": "合同透明", "score": 4, "description": "能明确提及合同将注明交付物、验收标准和业绩承诺，打消客户疑虑"}]}, {"dimension_name": "异议处理与推进动作", "score": 20, "core_goal": "承接客户的直接或间接异议，并引导进入签约或试点推进", "points": [{"point_name": "异议承接", "score": 6, "description": "能先认可客户感受（如“您说得对，价格确实需要反复核算”）"}, {"point_name": "针对性回应", "score": 5, "description": "能针对“价格高”提供价值拆解或灵活套餐，而非直接降价"}, {"point_name": "顾虑化解", "score": 5, "description": "能针对“怕后期扯皮”主动提出可写入合同的细化条款"}, {"point_name": "下一步推进", "score": 4, "description": "能提出具体推进动作，如安排线上演示、发送合同草案或约定深度沟通"}]}], "review_mode": "ai_auto", "formula": "总分 = 通用能力得分 + 阶段能力得分 - 扣分；一期暂不启用违规词扣分"}}', 'confirmed', '2026-06-22 03:42:26', '2026-06-22 03:42:26') ON DUPLICATE KEY UPDATE `session_id` = VALUES(`session_id`), `general_score` = VALUES(`general_score`), `stage_score` = VALUES(`stage_score`), `penalty_score` = VALUES(`penalty_score`), `final_score` = VALUES(`final_score`), `level` = VALUES(`level`), `is_passed` = VALUES(`is_passed`), `detail_json` = VALUES(`detail_json`), `review_status` = VALUES(`review_status`), `created_at` = VALUES(`created_at`), `updated_at` = VALUES(`updated_at`);

